"use client";
import { useState, useEffect } from "react";
import Image from "next/image";
import { Send, Bot, User, Sparkles } from "lucide-react";
import mascotImg from "@/assets/mascot.png";

type Message = { id: number; text: string; sender: "user" | "bot"; timestamp: string };

export default function ChatPage() {
    const [messages, setMessages] = useState<Message[]>([
        {
            id: 1,
            text: "Hello! I am your AI career mentor. I have full context of your academic performance, GitHub streaks, and recent Hackathon check-ins. How can I help you today?",
            sender: "bot",
            timestamp: "Just now",
        }
    ]);
    const [input, setInput] = useState("");
    const [showAnimation, setShowAnimation] = useState(true);

    const handleSend = () => {
        if (!input.trim()) return;
        const msg: Message = { id: Date.now(), text: input, sender: "user", timestamp: "Just now" };
        setMessages((prev) => [...prev, msg]);
        setInput("");

        // Simulate AI response
        setTimeout(() => {
            setMessages((prev) => [
                ...prev,
                {
                    id: Date.now() + 1,
                    text: "I see you're aiming for an AI Engineer role. Based on your current 88% overall attendance and CAT 1 performance, maintaining this momentum will guarantee you a spot in the placement training sandbox. Which topic should we revise today?",
                    sender: "bot",
                    timestamp: "Just now",
                }
            ]);
        }, 1500);
    };

    return (
        <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 200px)", position: "relative", animation: "fadeIn 0.5s ease" }}>

            {/* Fade In/Out Bot Animation on Mount */}
            {showAnimation && (
                <div className="chat-mascot">
                    <div style={{ padding: "16px 24px", background: "var(--bg-secondary)", border: "2px solid var(--accent)", borderRadius: "24px 24px 4px 24px", color: "var(--text-primary)", fontWeight: 600, boxShadow: "0 10px 30px rgba(0,0,0,0.5)", marginBottom: 40 }}>
                        "I'm here to guide you to the top! Let's chat!"
                    </div>
                    <div style={{ position: "relative", width: 120, height: 120, borderRadius: "50%", background: "var(--bg-tertiary)", border: "2px solid #3B82F6", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 0 20px rgba(37,99,235,0.8)" }}>
                        <Image
                            src={mascotImg}
                            alt="AI Mascot"
                            width={110}
                            height={110}
                            style={{ objectFit: "cover", mixBlendMode: "multiply" }}
                        />
                    </div>
                </div>
            )}

            {/* Header */}
            <div style={{ marginBottom: 24, padding: "24px", background: "var(--bg-tertiary)", borderRadius: 16, border: "1px solid var(--border-light)", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                    <h1 style={{ fontFamily: "var(--font-serif)", fontSize: "1.8rem", fontWeight: 400, color: "var(--text-primary)", marginBottom: 4 }}>
                        Chat with <span style={{ fontStyle: "italic", color: "var(--accent)" }}>AI</span>
                    </h1>
                    <p style={{ margin: 0, color: "var(--text-secondary)", fontSize: "0.95rem" }}>
                        Context-aware AI assistance mapped directly to your Skill DNA.
                    </p>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 16px", background: "rgba(37,99,235,0.1)", borderRadius: 100, border: "1px solid rgba(37,99,235,0.2)" }}>
                    <div style={{ width: 8, height: 8, borderRadius: "50%", background: "#22c55e", boxShadow: "0 0 10px #22c55e" }} />
                    <span style={{ fontSize: "0.85rem", color: "var(--accent)", fontWeight: 600 }}>Online Context Sync</span>
                </div>
            </div>

            {/* Chat Area */}
            <div className="stat-card" style={{ flex: 1, display: "flex", flexDirection: "column", background: "var(--bg-secondary)", borderRadius: 16, overflow: "hidden" }}>

                {/* Messages Container */}
                <div style={{ flex: 1, padding: 32, overflowY: "auto", display: "flex", flexDirection: "column", gap: 24 }}>
                    {messages.map((msg) => (
                        <div key={msg.id} style={{ display: "flex", gap: 16, alignSelf: msg.sender === "user" ? "flex-end" : "flex-start", maxWidth: "80%" }}>
                            {msg.sender === "bot" && (
                                <div style={{ width: 40, height: 40, borderRadius: "50%", background: "var(--accent-glow)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, border: "1px solid var(--accent)" }}>
                                    <Bot size={20} color="var(--accent)" />
                                </div>
                            )}
                            <div style={{ display: "flex", flexDirection: "column", gap: 6, alignItems: msg.sender === "user" ? "flex-end" : "flex-start" }}>
                                <div style={{
                                    padding: "16px 20px",
                                    background: msg.sender === "user" ? "var(--accent)" : "var(--bg-tertiary)",
                                    color: msg.sender === "user" ? "#FFFFFF" : "var(--text-primary)",
                                    borderRadius: msg.sender === "user" ? "20px 20px 4px 20px" : "20px 20px 20px 4px",
                                    fontSize: "0.95rem",
                                    lineHeight: 1.5,
                                    border: msg.sender === "bot" ? "1px solid var(--border-light)" : "none",
                                    boxShadow: msg.sender === "user" ? "0 4px 14px var(--accent-glow)" : "none"
                                }}>
                                    {msg.text}
                                </div>
                                <span style={{ fontSize: "0.75rem", color: "var(--text-muted)", margin: "0 8px" }}>{msg.timestamp}</span>
                            </div>
                            {msg.sender === "user" && (
                                <div style={{ width: 40, height: 40, borderRadius: "50%", background: "var(--bg-tertiary)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, border: "1px solid var(--border-light)" }}>
                                    <User size={20} color="var(--text-secondary)" />
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Input Area */}
                <div style={{ padding: 20, background: "var(--bg-tertiary)", borderTop: "1px solid var(--border-color)" }}>
                    {/* Suggestion Chips */}
                    <div style={{ display: "flex", gap: 12, marginBottom: 16, overflowX: "auto", paddingBottom: 8 }}>
                        {["Explain recursion in Python", "Review my CAT 1 mistakes", "Suggest a machine learning mini-project"].map((chip, i) => (
                            <button
                                key={i}
                                onClick={() => setInput(chip)}
                                style={{ background: "rgba(255,255,255,0.03)", border: "1px solid var(--border-light)", color: "var(--text-secondary)", padding: "8px 16px", borderRadius: 100, fontSize: "0.85rem", cursor: "pointer", whiteSpace: "nowrap", transition: "all 0.2s" }}
                                onMouseEnter={(e) => { e.currentTarget.style.color = "var(--text-primary)"; e.currentTarget.style.background = "rgba(255,255,255,0.08)"; }}
                                onMouseLeave={(e) => { e.currentTarget.style.color = "var(--text-secondary)"; e.currentTarget.style.background = "rgba(255,255,255,0.03)"; }}
                            >
                                {chip}
                            </button>
                        ))}
                    </div>

                    <div style={{ position: "relative" }}>
                        <div style={{ position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)", color: "var(--accent)" }}>
                            <Sparkles size={20} />
                        </div>
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={(e) => e.key === "Enter" && handleSend()}
                            placeholder="Ask anything about your courses, career, or coding goals..."
                            style={{
                                width: "100%",
                                padding: "16px 16px 16px 48px",
                                background: "var(--bg-secondary)",
                                border: "1px solid var(--border-color)",
                                borderRadius: 12,
                                color: "var(--text-primary)",
                                fontSize: "1rem",
                                outline: "none"
                            }}
                        />
                        <button
                            onClick={handleSend}
                            disabled={!input.trim()}
                            style={{
                                position: "absolute",
                                right: 8,
                                top: 8,
                                bottom: 8,
                                background: input.trim() ? "var(--accent)" : "transparent",
                                color: input.trim() ? "#FFF" : "var(--text-muted)",
                                border: "none",
                                borderRadius: 8,
                                padding: "0 20px",
                                cursor: input.trim() ? "pointer" : "default",
                                transition: "all 0.2s"
                            }}
                        >
                            <Send size={18} />
                        </button>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import Image from "next/image";
import { usePathname } from "next/navigation";
import { sampleStudent } from "@/lib/data";
import logo from "@/assets/logo.png";
import { LayoutDashboard, Fingerprint, LineChart, AlertCircle, Map as MapIcon, Bot, FileText, ChevronLeft, ChevronRight, Bell } from "lucide-react";
import mascotImg from "@/assets/mascot.png";

const NAV_ITEMS = [
    { id: "home", path: "/dashboard", icon: <LayoutDashboard size={20} strokeWidth={1.5} />, label: "Overview" },
    { id: "projects", path: "/dashboard/projects", icon: <Bot size={20} strokeWidth={1.5} />, label: "Projects & Hackathons" },
    { id: "assessments", path: "/dashboard/assessments", icon: <LineChart size={20} strokeWidth={1.5} />, label: "Assessments" },
    { id: "roadmap", path: "/dashboard/roadmap", icon: <MapIcon size={20} strokeWidth={1.5} />, label: "Roadmap" },
    { id: "mentor", path: "/dashboard/mentor", icon: <FileText size={20} strokeWidth={1.5} />, label: "Mentor Guide" },
    { id: "chat", path: "/dashboard/chat", icon: <Bot size={20} strokeWidth={1.5} />, label: "Chat with AI" },
    { id: "logs", path: "/dashboard/logs", icon: <FileText size={20} strokeWidth={1.5} />, label: "Logs / Upload" },
    { id: "resume", path: "/dashboard/resume", icon: <AlertCircle size={20} strokeWidth={1.5} />, label: "Resume Optimizer" },
    { id: "connect", path: "/dashboard/connect", icon: <Fingerprint size={20} strokeWidth={1.5} />, label: "Alumni & Connect" },
];

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

    const xpTotal = 350;
    const xpMax = 500;

    return (
        <div style={{ display: "flex", height: "100vh", overflow: "hidden", background: "var(--bg-primary)" }}>
            {/* ===== SIDEBAR ===== */}
            <aside
                style={{
                    width: sidebarCollapsed ? 80 : 260,
                    height: "100%",
                    background: "var(--bg-secondary)",
                    borderRight: "1px solid var(--border-color)",
                    display: "flex",
                    flexDirection: "column",
                    transition: "width 0.3s cubic-bezier(0.2, 0, 0, 1)",
                    flexShrink: 0,
                    zIndex: 50,
                }}
                className="hide-mobile"
            >
                {/* Logo Area */}
                <div style={{ padding: sidebarCollapsed ? "24px 0" : "24px", display: "flex", alignItems: "center", justifyContent: sidebarCollapsed ? "center" : "space-between", borderBottom: "1px solid var(--border-light)" }}>
                    <Link href="/dashboard" style={{ display: "flex", alignItems: "center", gap: 12, textDecoration: "none" }}>
                        <Image src={logo} alt="Logo" width={32} height={32} style={{ borderRadius: "8px", flexShrink: 0 }} />
                        {!sidebarCollapsed && (
                            <span style={{ fontFamily: "var(--font-serif)", fontWeight: 500, fontSize: "1.1rem", color: "var(--text-primary)", whiteSpace: "nowrap" }}>
                                Skill GPS
                            </span>
                        )}
                    </Link>
                </div>

                {/* Nav */}
                <nav style={{ flex: 1, padding: "24px 12px", display: "flex", flexDirection: "column", gap: 8, overflowY: "auto" }}>
                    {NAV_ITEMS.map((item) => {
                        const isActive = pathname === item.path;
                        return (
                            <Link
                                key={item.id}
                                href={item.path}
                                className={`sidebar-nav-item ${isActive ? "active" : ""}`}
                                style={{
                                    justifyContent: sidebarCollapsed ? "center" : "flex-start",
                                    padding: sidebarCollapsed ? "12px" : "12px 16px",
                                }}
                                title={sidebarCollapsed ? item.label : undefined}
                            >
                                <div style={{ color: isActive ? "var(--text-primary)" : "var(--text-secondary)" }}>
                                    {item.icon}
                                </div>
                                {!sidebarCollapsed && <span style={{ fontWeight: isActive ? 500 : 400 }}>{item.label}</span>}
                            </Link>
                        );
                    })}
                </nav>

                <button
                    onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
                    style={{ background: "none", border: "1px solid var(--border-light)", color: "var(--text-secondary)", cursor: "pointer", padding: "8px", margin: "16px", borderRadius: "8px", transition: "all 0.2s", display: "flex", justifyContent: "center" }}
                    aria-label="Toggle Sidebar"
                >
                    {sidebarCollapsed ? <ChevronRight size={18} /> : <ChevronLeft size={18} />}
                </button>

                {/* Mascot + Light minimal user section */}
                {!sidebarCollapsed && (
                    <div style={{ padding: "0 20px" }}>
                        <div style={{ padding: "16px", background: "var(--bg-tertiary)", border: "1px solid var(--border-light)", borderRadius: 12, display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
                            <Image src={mascotImg} alt="Mascot" width={36} height={36} style={{ borderRadius: "50%", background: "var(--bg-secondary)", border: "1px solid var(--border-color)" }} />
                            <div>
                                <span style={{ fontSize: "0.8rem", fontWeight: 600, color: "var(--text-primary)" }}>Level 12</span>
                                <div style={{ fontSize: "0.7rem", color: "var(--text-muted)" }}>2,450 XP</div>
                            </div>
                        </div>
                    </div>
                )}
                <div style={{ padding: sidebarCollapsed ? "16px 0" : "16px 20px", display: "flex", alignItems: "center", justifyContent: sidebarCollapsed ? "center" : "flex-start", gap: 12, borderTop: "1px solid var(--border-light)", background: "var(--bg-tertiary)" }}>
                    {!sidebarCollapsed && (
                        <div style={{ display: "flex", flexDirection: "column" }}>
                            <span style={{ fontWeight: 500, fontSize: "0.85rem", color: "var(--text-primary)" }}>{sampleStudent.name}</span>
                            <span style={{ fontSize: "0.75rem", color: "var(--text-secondary)" }}>{sampleStudent.department}</span>
                        </div>
                    )}
                </div>
            </aside>

            {/* ===== MAIN CONTENT ===== */}
            <main style={{ flex: 1, height: "100%", overflowY: "auto", display: "flex", flexDirection: "column", position: "relative" }}>
                {/* Top header */}
                <header style={{ padding: "0 40px", height: "80px", borderBottom: "1px solid var(--border-color)", display: "flex", justifyContent: "space-between", alignItems: "center", background: "var(--bg-secondary)", position: "sticky", top: 0, zIndex: 40 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
                        <h2 style={{ fontFamily: "var(--font-serif)", fontSize: "1.25rem", fontWeight: 500, color: "var(--text-primary)" }}>
                            {NAV_ITEMS.find(n => n.path === pathname)?.label || "Overview"}
                        </h2>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
                        <span className="badge">Semester {sampleStudent.semester}</span>
                        <button style={{ background: "none", border: "none", cursor: "pointer", color: "var(--text-secondary)" }}>
                            <Bell size={20} strokeWidth={1.5} />
                        </button>
                        <div style={{ width: 36, height: 36, borderRadius: "50%", background: "var(--bg-tertiary)", border: "1px solid var(--border-light)", display: "flex", alignItems: "center", justifyContent: "center", color: "var(--text-primary)", fontWeight: 500, fontFamily: "var(--font-serif)", fontSize: "1rem" }}>
                            {sampleStudent.name.charAt(0)}
                        </div>
                    </div>
                </header>

                <div style={{ flex: 1, padding: "40px", maxWidth: "1200px", margin: "0 auto", width: "100%" }}>

                    {/* Dynamic Mascot Voice (Duolingo Style) */}
                    <div style={{ background: "var(--bg-tertiary)", border: "1px solid var(--border-light)", padding: "16px 20px", borderRadius: 16, marginBottom: 32, display: "flex", alignItems: "center", gap: 16 }}>
                        <Image src={mascotImg} alt="Mascot" width={50} height={50} style={{ borderRadius: "50%", background: "var(--bg-secondary)", border: "1px solid var(--border-color)" }} />
                        <div>
                            {pathname === '/dashboard' && <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"Here's your summary for today. Your consistency is amazing, keep solving those problems!"</p>}
                            {pathname === '/dashboard/projects' && <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"Hackathons are a great way to boost XP. I see you're on a 30-day streak!"</p>}
                            {pathname === '/dashboard/assessments' && <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"Let's review your internal marks and attendance. Staying above 80% is the goal!"</p>}
                            {pathname === '/dashboard/roadmap' && <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"You're making great progress! What goal are we smashing next?"</p>}
                            {pathname === '/dashboard/mentor' && <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"It's time for our check-in! Let's review the feedback together."</p>}
                            {!(pathname === '/dashboard' || pathname === '/dashboard/projects' || pathname === '/dashboard/assessments' || pathname === '/dashboard/roadmap' || pathname === '/dashboard/mentor') && (
                                <p style={{ margin: 0, fontSize: "0.95rem", color: "var(--text-primary)" }}>"Every step you take brings you closer to your career goals. You've got this!"</p>
                            )}
                        </div>
                    </div>

                    {children}
                </div>

                {/* Mobile nav indicator */}
                <nav style={{ display: "none", borderTop: "1px solid var(--border-color)", padding: "12px 8px", background: "var(--bg-secondary)", justifyContent: "space-around" }} className="mobile-nav">
                    {NAV_ITEMS.slice(0, 5).map((item) => {
                        const isActive = pathname === item.path;
                        return (
                            <Link
                                key={item.id}
                                href={item.path}
                                style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, textDecoration: "none", color: isActive ? "var(--accent)" : "var(--text-secondary)", fontSize: "0.7rem", fontWeight: isActive ? 500 : 400 }}
                            >
                                {item.icon}
                                {item.label}
                            </Link>
                        );
                    })}
                </nav>
            </main>
        </div>
    );
}

