"use client";
import { useState } from "react";
import { resumeScore } from "@/lib/data";
import { CheckCircle2, AlertCircle, FileText, UploadCloud, TrendingUp, Sparkles, LayoutPanelLeft } from "lucide-react";

export default function ResumePage() {
    const [uploadedFile, setUploadedFile] = useState<string | null>(null);
    const [analyzing, setAnalyzing] = useState(false);
    const [showResults, setShowResults] = useState(true);

    const handleUpload = async () => {
        setAnalyzing(true);
        await new Promise((r) => setTimeout(r, 2000));
        setAnalyzing(false);
        setShowResults(true);
        setUploadedFile("Arjun_Resume_2026.pdf");
    };

    const overallColor = resumeScore.overall >= 75 ? "#2563EB" : resumeScore.overall >= 55 ? "#FF8C00" : "#ef4444";

    return (
        <div style={{ maxWidth: 1000, margin: "0 auto", animation: "fadeIn 0.5s ease" }}>
            {/* Header */}
            <div style={{ marginBottom: 40 }}>
                <h1 style={{ fontFamily: "var(--font-serif)", fontSize: "2.5rem", fontWeight: 400, color: "var(--text-primary)", marginBottom: 8 }}>
                    Resume <span style={{ fontStyle: "italic", color: "var(--text-secondary)" }}>Optimizer</span>
                </h1>
                <p style={{ color: "var(--text-secondary)", fontSize: "1.05rem" }}>
                    ATS score breakdowns, live suggestions, and AI rewrites.
                </p>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 32, alignItems: "start" }}>

                {/* Column 1: Upload & Overall Score */}
                <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>

                    {/* Upload Card */}
                    <div className="stat-card" style={{ padding: 24 }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                            <h3 style={{ fontSize: "1.1rem", fontWeight: 500, color: "var(--text-primary)", display: "flex", alignItems: "center", gap: 8 }}><FileText size={20} /> Current Resume</h3>
                            {uploadedFile && <span className="badge">Analyzed</span>}
                        </div>
                        {uploadedFile ? (
                            <div style={{ padding: 16, background: "var(--bg-tertiary)", borderRadius: 12, border: "1px solid var(--border-light)", display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                                <span style={{ fontSize: "0.95rem", color: "var(--accent)", fontWeight: 500 }}>{uploadedFile}</span>
                                <CheckCircle2 size={18} color="#22c55e" />
                            </div>
                        ) : (
                            <p style={{ fontSize: "0.85rem", color: "var(--text-muted)", marginBottom: 16 }}>No resume uploaded. Upload a PDF to get ATS feedback.</p>
                        )}
                        <button onClick={handleUpload} className="btn-primary" style={{ width: "100%", display: "flex", justifyContent: "center", gap: 8 }}>
                            {analyzing ? "Analyzing Document..." : <><UploadCloud size={16} /> Upload New Version</>}
                        </button>
                    </div>

                    {/* Overall Score Card */}
                    {showResults && (
                        <div className="stat-card" style={{ padding: 32, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", background: "linear-gradient(135deg, var(--bg-tertiary), var(--bg-secondary))" }}>
                            <h3 style={{ fontSize: "1.1rem", fontWeight: 500, color: "var(--text-primary)", marginBottom: 16 }}>ATS Match Probability</h3>

                            <div style={{ position: "relative", width: 140, height: 140, display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "50%", background: `conic-gradient(${overallColor} ${resumeScore.overall}%, var(--bg-tertiary) ${resumeScore.overall}% 100%)`, marginBottom: 16 }}>
                                <div style={{ width: 120, height: 120, background: "var(--bg-secondary)", borderRadius: "50%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
                                    <span style={{ fontFamily: "var(--font-serif)", fontSize: "2rem", fontWeight: 500, color: "var(--text-primary)" }}>{resumeScore.overall}%</span>
                                    <span style={{ fontSize: "0.75rem", color: "var(--text-muted)", textTransform: "uppercase" }}>Score</span>
                                </div>
                            </div>

                            <p style={{ fontSize: "0.9rem", color: "var(--text-secondary)", marginBottom: 20 }}>
                                Your resume is scoring decently, but it lacks some critical keywords for AI engineering roles.
                            </p>

                            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, width: "100%" }}>
                                <div style={{ background: "var(--bg-primary)", padding: 12, borderRadius: 8, border: "1px solid var(--border-light)" }}>
                                    <div style={{ fontSize: "1.2rem", fontWeight: 600, color: "var(--text-primary)" }}>{resumeScore.atsScore}%</div>
                                    <div style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>Raw ATS Parse</div>
                                </div>
                                <div style={{ background: "var(--bg-primary)", padding: 12, borderRadius: 8, border: "1px solid var(--border-light)" }}>
                                    <div style={{ fontSize: "1.2rem", fontWeight: 600, color: "var(--text-primary)" }}>{resumeScore.suggestions.length}</div>
                                    <div style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>Action Items</div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Column 2: Breakdowns & Tips */}
                <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>

                    {/* Section Breakdown */}
                    {showResults && (
                        <div className="stat-card" style={{ padding: 24 }}>
                            <h3 style={{ fontSize: "1.1rem", fontWeight: 500, color: "var(--text-primary)", marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}><LayoutPanelLeft size={20} /> Section Breakdown</h3>
                            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                                {resumeScore.breakdown.map((item) => (
                                    <div key={item.category}>
                                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                                            <span style={{ fontSize: "0.9rem", color: "var(--text-primary)" }}>{item.category}</span>
                                            <span style={{ fontSize: "0.85rem", fontWeight: 600, color: item.score >= 80 ? "#22c55e" : item.score >= 50 ? "#FF8C00" : "#ef4444" }}>{item.score}%</span>
                                        </div>
                                        <div style={{ height: 6, background: "var(--bg-tertiary)", borderRadius: 10 }}>
                                            <div style={{ width: `${item.score}%`, height: "100%", background: item.score >= 80 ? "#22c55e" : item.score >= 50 ? "#FF8C00" : "#ef4444", borderRadius: 10 }} />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Improvement Suggestions */}
                    {showResults && (
                        <div className="stat-card" style={{ padding: 24 }}>
                            <h3 style={{ fontSize: "1.1rem", fontWeight: 500, color: "var(--text-primary)", marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}><Sparkles size={20} /> AI Recommendations</h3>
                            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                                {resumeScore.suggestions.map((tip, i) => (
                                    <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 12, padding: 16, background: "var(--bg-tertiary)", border: "1px solid var(--border-light)", borderRadius: 8 }}>
                                        <AlertCircle size={16} color={i < 2 ? "#ef4444" : "#FF8C00"} style={{ marginTop: 2, flexShrink: 0 }} />
                                        <div style={{ fontSize: "0.85rem", color: "var(--text-secondary)", lineHeight: 1.5 }}>{tip}</div>
                                    </div>
                                ))}
                            </div>
                            <button className="btn-primary" style={{ width: "100%", marginTop: 20, padding: 12, background: "transparent", border: "1px dashed var(--accent)", color: "var(--accent)", display: "flex", justifyContent: "center", gap: 8 }}>
                                <Sparkles size={16} /> Auto-Rewrite with AI
                            </button>
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
}

"use client";
import { useState, useEffect, useCallback } from "react";
import { careerSimulation, sampleStudent } from "@/lib/data";

type SimFactor = { id: string; label: string; icon: string; current: number; max: number; impactPerUnit: number; unit: string };

export default function SimulationPage() {
    const [values, setValues] = useState<Record<string, number>>(() =>
        Object.fromEntries(careerSimulation.factors.map((f) => [f.id, f.current]))
    );
    const [probability, setProbability] = useState(careerSimulation.baselineProbability);
    const [prevProbability, setPrevProbability] = useState(careerSimulation.baselineProbability);
    const [mascotMood, setMascotMood] = useState<"idle" | "celebrate" | "excited" | "thinking">("idle");
    const [mascotMsg, setMascotMsg] = useState("Drag the sliders to simulate your future! Watch your AI Engineer probability change live ");
    const [animatedProbability, setAnimatedProbability] = useState(careerSimulation.baselineProbability);
    const [celebrationShown, setCelebrationShown] = useState(false);

    const computeProbability = useCallback((vals: Record<string, number>) => {
        let bonus = 0;
        careerSimulation.factors.forEach((f) => {
            const delta = vals[f.id] - f.current;
            bonus += delta * f.impactPerUnit;
        });
        return Math.min(99, Math.max(careerSimulation.baselineProbability, careerSimulation.baselineProbability + bonus));
    }, []);

    useEffect(() => {
        const newProb = computeProbability(values);
        setPrevProbability(probability);
        setProbability(newProb);

        // Animate number
        const start = animatedProbability;
        const end = newProb;
        const steps = 20;
        let step = 0;
        const timer = setInterval(() => {
            step++;
            setAnimatedProbability(start + ((end - start) * step) / steps);
            if (step >= steps) clearInterval(timer);
        }, 20);

        // Mascot reactions
        if (newProb >= 80 && !celebrationShown) {
            setMascotMood("celebrate");
            setMascotMsg("AMAZING! You're 80%+ ready!  Top companies would love to interview you now!");
            setCelebrationShown(true);
        } else if (newProb >= 65) {
            setMascotMood("excited");
            setMascotMsg(`${Math.round(newProb)}% ready! You're almost there! Keep adding more achievements! `);
        } else if (newProb > careerSimulation.baselineProbability + 10) {
            setMascotMood("excited");
            setMascotMsg(`Great progress! Up to ${Math.round(newProb)}%! Add an internship to see a big jump! `);
        } else {
            setMascotMood("thinking");
            setMascotMsg("Tip: Adding an internship gives the biggest probability boost! ");
        }

        return () => clearInterval(timer);
    }, [values]);

    const handleSlider = (id: string, val: number) => {
        setValues((prev) => ({ ...prev, [id]: val }));
    };

    const reset = () => {
        setValues(Object.fromEntries(careerSimulation.factors.map((f) => [f.id, f.current])));
        setCelebrationShown(false);
    };

    const gain = Math.round(animatedProbability) - careerSimulation.baselineProbability;

    const getColor = (prob: number) => {
        if (prob >= 80) return "#00D4FF";
        if (prob >= 65) return "#0066FF";
        if (prob >= 50) return "#FF8C00";
        return "#FF6B00";
    };

    const probColor = getColor(animatedProbability);

    const ROLE_THRESHOLDS = [
        { role: "Junior Developer", threshold: 30, icon: "" },
        { role: "ML Engineer", threshold: 55, icon: "" },
        { role: "AI Engineer", threshold: 70, icon: "" },
        { role: "Senior AI Engineer", threshold: 85, icon: "" },
        { role: "AI Architect", threshold: 95, icon: "" },
    ];

    return (
        <div style={{ maxWidth: 1100, margin: "0 auto" }}>
            {/* Header */}
            <div style={{ marginBottom: 28 }}>
                <span className="badge badge-orange" style={{ marginBottom: 12, display: "inline-flex" }}> Career Simulation</span>
                <h1 style={{ fontFamily: "var(--font-display)", fontSize: "2rem", fontWeight: 800, marginBottom: 6 }}>
                    Simulate Your <span className="text-gradient-orange">Career Path</span>
                </h1>
                <p style={{ color: "var(--white-muted)" }}>
                    Drag the sliders to add achievements and watch your probability score update in real time
                </p>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 24 }}>
                {/* Left ΓÇô Sliders */}
                <div>
                    <div className="glass-card" style={{ padding: 28 }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
                            <h3 style={{ fontWeight: 700, fontSize: "1rem" }}>Add Achievements</h3>
                            <button
                                onClick={reset}
                                style={{ background: "transparent", border: "1px solid transparent", color: "var(--orange-primary)", borderRadius: 8, padding: "6px 14px", cursor: "pointer", fontSize: "0.8rem", fontWeight: 600 }}
                            >
                                Reset
                            </button>
                        </div>

                        {careerSimulation.factors.map((factor: SimFactor) => {
                            const val = values[factor.id];
                            const pct = ((val - factor.current) / (factor.max - factor.current)) * 100;
                            const impact = Math.round((val - factor.current) * factor.impactPerUnit);

                            return (
                                <div key={factor.id} style={{ marginBottom: 28 }}>
                                    {/* Label */}
                                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
                                        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                            <span style={{ fontSize: "1.3rem" }}>{factor.icon}</span>
                                            <div>
                                                <div style={{ fontWeight: 600, fontSize: "0.9rem" }}>{factor.label}</div>
                                                <div style={{ color: "var(--white-muted)", fontSize: "0.75rem" }}>
                                                    Current: {factor.current} {factor.unit}
                                                </div>
                                            </div>
                                        </div>
                                        <div style={{ textAlign: "right" }}>
                                            <div style={{ fontFamily: "var(--font-display)", fontSize: "1.3rem", fontWeight: 800, color: val > factor.current ? "#00D4FF" : "var(--white-muted)" }}>
                                                {val}
                                            </div>
                                            {impact > 0 && (
                                                <div style={{ color: "#00D4FF", fontSize: "0.72rem", fontWeight: 700 }}>
                                                    +{impact}% boost
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Slider */}
                                    <div style={{ position: "relative" }}>
                                        {/* Track bg */}
                                        <div style={{ height: 6, borderRadius: 3, background: "var(--bg-tertiary)", position: "relative", marginBottom: 4 }}>
                                            {/* Current marker */}
                                            <div
                                                style={{
                                                    position: "absolute",
                                                    left: `${(factor.current / factor.max) * 100}%`,
                                                    top: -3,
                                                    width: 2,
                                                    height: 12,
                                                    background: "rgba(255,255,255,0.3)",
                                                    borderRadius: 1,
                                                }}
                                            />
                                            {/* Fill */}
                                            <div
                                                style={{
                                                    height: "100%",
                                                    borderRadius: 3,
                                                    background: val > factor.current
                                                        ? "transparent"
                                                        : "rgba(255,255,255,0.1)",
                                                    width: `${(val / factor.max) * 100}%`,
                                                    transition: "width 0.1s",
                                                }}
                                            />
                                        </div>
                                        <input
                                            type="range"
                                            min={factor.current}
                                            max={factor.max}
                                            value={val}
                                            onChange={(e) => handleSlider(factor.id, Number(e.target.value))}
                                            className="custom-slider"
                                            style={{ position: "absolute", top: -3, left: 0, right: 0, opacity: 0, cursor: "pointer", height: 12 }}
                                        />
                                        {/* Custom slider visual */}
                                        <input
                                            type="range"
                                            min={factor.current}
                                            max={factor.max}
                                            value={val}
                                            onChange={(e) => handleSlider(factor.id, Number(e.target.value))}
                                            style={{
                                                width: "100%",
                                                height: 6,
                                                borderRadius: 3,
                                                appearance: "none",
                                                background: "var(--bg-tertiary)",
                                                outline: "none",
                                                cursor: "pointer",
                                            }}
                                        />
                                        <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4, fontSize: "0.72rem", color: "var(--white-subtle)" }}>
                                            <span>{factor.current} (current)</span>
                                            <span>{factor.max} (max)</span>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Right ΓÇô Probability + Mascot */}
                <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                    {/* Probability Card */}
                    <div
                        className="glass-card"
                        style={{
                            padding: 28,
                            textAlign: "center",
                            border: `1px solid ${probColor}30`,
                            background: `${probColor}06`,
                            position: "relative",
                            overflow: "hidden",
                        }}
                    >
                        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: 200, height: 200, borderRadius: "50%", background: `radial-gradient(circle, ${probColor}08, transparent)`, pointerEvents: "none" }} />

                        <div style={{ fontSize: "0.8rem", color: "var(--white-muted)", textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>
                            AI Engineer Readiness
                        </div>

                        {/* Big probability ring */}
                        <div style={{ position: "relative", width: 160, height: 160, margin: "0 auto 16px" }}>
                            <svg width="160" height="160" viewBox="0 0 160 160">
                                <circle cx="80" cy="80" r="68" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="10" />
                                <circle
                                    cx="80"
                                    cy="80"
                                    r="68"
                                    fill="none"
                                    stroke={probColor}
                                    strokeWidth="10"
                                    strokeLinecap="round"
                                    strokeDasharray={`${2 * Math.PI * 68}`}
                                    strokeDashoffset={`${2 * Math.PI * 68 * (1 - animatedProbability / 100)}`}
                                    transform="rotate(-90 80 80)"
                                    style={{ transition: "stroke-dashoffset 0.05s linear, stroke 0.5s ease" }}
                                />
                                <defs>
                                    <linearGradient id="simGrad" x1="0%" y1="0%" x2="100%" y2="0%">
                                        <stop offset="0%" stopColor="#00D4FF" />
                                        <stop offset="100%" stopColor={probColor} />
                                    </linearGradient>
                                </defs>
                                <text x="80" y="72" textAnchor="middle" fill="white" fontSize="30" fontWeight="800" fontFamily="Syne">
                                    {Math.round(animatedProbability)}%
                                </text>
                                <text x="80" y="92" textAnchor="middle" fill="#6B7A99" fontSize="11">
                                    Ready
                                </text>
                                {gain > 0 && (
                                    <text x="80" y="108" textAnchor="middle" fill="#00D4FF" fontSize="11" fontWeight="700">
                                        +{gain}% gained!
                                    </text>
                                )}
                            </svg>
                        </div>

                        <div style={{ fontFamily: "var(--font-display)", fontSize: "1.1rem", fontWeight: 700, marginBottom: 4 }}>
                            {sampleStudent.careerTarget}
                        </div>
                        {gain > 0 && (
                            <div style={{ color: "#00D4FF", fontSize: "0.85rem", fontWeight: 700 }}>
                                Γåæ {gain}% from baseline ({careerSimulation.baselineProbability}%)
                            </div>
                        )}
                    </div>

                    {/* Role progression */}
                    <div className="glass-card" style={{ padding: 20 }}>
                        <h3 style={{ fontWeight: 700, fontSize: "0.88rem", marginBottom: 14, color: "var(--white-muted)" }}>
                            Role Progression
                        </h3>
                        {ROLE_THRESHOLDS.map((r) => (
                            <div
                                key={r.role}
                                style={{
                                    display: "flex",
                                    alignItems: "center",
                                    gap: 10,
                                    padding: "8px 0",
                                    borderBottom: "1px solid rgba(255,255,255,0.04)",
                                    opacity: animatedProbability >= r.threshold ? 1 : 0.4,
                                }}
                            >
                                <span style={{ fontSize: "1rem" }}>{r.icon}</span>
                                <div style={{ flex: 1, fontSize: "0.82rem", fontWeight: 500 }}>{r.role}</div>
                                <div style={{ fontSize: "0.75rem", color: animatedProbability >= r.threshold ? "#00D4FF" : "var(--white-subtle)", fontWeight: 700 }}>
                                    {r.threshold}%+
                                </div>
                                {animatedProbability >= r.threshold && (
                                    <span style={{ color: "#00D4FF", fontSize: "0.9rem" }}></span>
                                )}
                            </div>
                        ))}
                    </div>

                    {/* Mascot */}
                    <div style={{ display: "flex", justifyContent: "center" }}>
                        
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from "react";
import {
    RadarChart, PolarGrid, PolarAngleAxis, Radar, ResponsiveContainer, Tooltip,
} from "recharts";
import { skillDNA } from "@/lib/data";

const TRAIT_DETAILS: Record<string, { desc: string; tips: string[]; color: string }> = {
    Analytical: {
        color: "#00D4FF",
        desc: "Your ability to break down complex problems and interpret data patterns.",
        tips: ["Solve 3 data puzzles weekly", "Take a Statistics course", "Practice data interpretation"],
    },
    Technical: {
        color: "#0066FF",
        desc: "Your coding, system building, and tool-usage proficiency.",
        tips: ["Build 2 more GitHub projects", "Learn system design basics", "Contribute to open source"],
    },
    Creative: {
        color: "#FF8C00",
        desc: "Your ability to think outside the box and innovate new solutions.",
        tips: ["Participate in hackathons", "Design a personal project", "Study UX/UI principles"],
    },
    Leadership: {
        color: "#FF6B00",
        desc: "Your ability to guide teams, manage projects, and influence decisions.",
        tips: ["Lead a team project", "Join a student club", "Mentor a junior student"],
    },
    Communication: {
        color: "#00B4CC",
        desc: "How effectively you express ideas verbally, in writing, and in presentations.",
        tips: ["Write 1 tech blog/month", "Present at a seminar", "Practice mock interviews"],
    },
    "Problem Solving": {
        color: "#0099FF",
        desc: "Your structured approach to identifying, analyzing, and resolving challenges.",
        tips: ["Solve 5 LeetCode problems/week", "Study algorithms deeply", "Join competitive programming"],
    },
};

export default function SkillDNAPage() {
    const [selectedTrait, setSelectedTrait] = useState<string | null>(null);
    const [animatedValues, setAnimatedValues] = useState(skillDNA.traits.map(() => 0));
    const [mascotMood, setMascotMood] = useState<"celebrate" | "thinking" | "excited" | "idle">("idle");
    const [mascotMsg, setMascotMsg] = useState("Your Skill DNA is unique to you!  Let's decode what makes you powerful.");

    useEffect(() => {
        // Animate radar chart values
        let step = 0;
        const timer = setInterval(() => {
            step++;
            setAnimatedValues(skillDNA.traits.map((t) => Math.min(t.value, Math.floor((t.value * step) / 40))));
            if (step >= 40) clearInterval(timer);
        }, 30);
        setTimeout(() => {
            setMascotMood("celebrate");
            setMascotMsg("Your Technical score is 85%! You're a born builder  Let's strengthen your weak areas too!");
        }, 1500);
        return () => clearInterval(timer);
    }, []);

    const chartData = skillDNA.traits.map((t, i) => ({ ...t, value: animatedValues[i] }));

    const selected = selectedTrait ? TRAIT_DETAILS[selectedTrait] : null;
    const selectedTraitData = skillDNA.traits.find((t) => t.skill === selectedTrait);

    const getTraitComment = (val: number) => {
        if (val >= 80) return { label: "Expert", color: "#00D4FF" };
        if (val >= 60) return { label: "Proficient", color: "#0066FF" };
        if (val >= 40) return { label: "Developing", color: "#FF8C00" };
        return { label: "Beginner", color: "#FF3B3B" };
    };

    return (
        <div style={{ maxWidth: 1100, margin: "0 auto" }}>
            {/* Header */}
            <div style={{ marginBottom: 28 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 8 }}>
                    <span className="badge badge-cyan"> Skill DNA</span>
                </div>
                <h1 style={{ fontFamily: "var(--font-display)", fontSize: "2rem", fontWeight: 800, marginBottom: 6 }}>
                    Your Skill <span className="text-gradient-cyan">DNA</span>
                </h1>
                <p style={{ color: "var(--white-muted)" }}>
                    Your unique competency fingerprint across 6 core dimensions
                </p>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24 }}>
                {/* Left ΓÇô Radar Chart */}
                <div>
                    {/* Dominant DNA badge */}
                    <div
                        className="glass-card-cyan"
                        style={{ padding: "16px 20px", marginBottom: 20, display: "flex", alignItems: "center", gap: 14 }}
                    >
                        <div style={{ fontSize: "2.5rem" }}></div>
                        <div>
                            <div style={{ fontSize: "0.75rem", color: "var(--cyan-primary)", textTransform: "uppercase", letterSpacing: 1, fontWeight: 700 }}>
                                Your Dominant DNA
                            </div>
                            <div style={{ fontFamily: "var(--font-display)", fontSize: "1.3rem", fontWeight: 800 }}>
                                {skillDNA.dominant}
                            </div>
                        </div>
                        <div style={{ marginLeft: "auto" }}>

                        </div>
                    </div>

                    {/* Radar Chart */}
                    <div
                        className="glass-card"
                        style={{ padding: 24, height: 380, position: "relative" }}
                    >
                        {/* Glow rings behind chart */}
                        <div
                            style={{
                                position: "absolute",
                                top: "50%",
                                left: "50%",
                                transform: "translate(-50%, -50%)",
                                width: 280,
                                height: 280,
                                borderRadius: "50%",
                                background: "radial-gradient(circle, transparent, transparent 70%)",
                                pointerEvents: "none",
                            }}
                        />
                        <ResponsiveContainer width="100%" height="100%">
                            <RadarChart data={chartData} outerRadius={120}>
                                <PolarGrid stroke="rgba(255,255,255,0.06)" />
                                <PolarAngleAxis
                                    dataKey="skill"
                                    tick={{ fill: "#A8B4CC", fontSize: 12, fontFamily: "Space Grotesk", fontWeight: 600 }}
                                    onClick={(e: { value: string }) => {
                                        setSelectedTrait(e.value);
                                        setMascotMood("thinking");
                                        setMascotMsg(`Let me analyze your ${e.value} traits... `);
                                    }}
                                    style={{ cursor: "pointer" }}
                                />
                                <Radar
                                    name="Your Skills"
                                    dataKey="value"
                                    stroke="#00D4FF"
                                    fill="transparent"
                                    fillOpacity={1}
                                    strokeWidth={2}
                                    dot={{ r: 5, fill: "#00D4FF", strokeWidth: 0 }}
                                />
                                <Tooltip
                                    contentStyle={{
                                        background: "#111318",
                                        border: "1px solid transparent",
                                        borderRadius: 10,
                                        color: "white",
                                        fontSize: "0.85rem",
                                    }}
                                    formatter={(val: unknown) => [`${val}%`, "Score"] as [string, string]}
                                />
                            </RadarChart>
                        </ResponsiveContainer>
                    </div>

                    {/* Mascot message */}
                    <div style={{ marginTop: 16 }}>

                    </div>
                </div>

                {/* Right ΓÇô trait list + detail */}
                <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                    {/* Trait list */}
                    <div className="glass-card" style={{ padding: 20 }}>
                        <h3 style={{ fontWeight: 700, fontSize: "0.95rem", marginBottom: 16 }}>
                            Click a trait to explore Γåô
                        </h3>
                        {skillDNA.traits.map((trait, i) => {
                            const detail = TRAIT_DETAILS[trait.skill];
                            const comment = getTraitComment(trait.value);
                            return (
                                <div
                                    key={trait.skill}
                                    onClick={() => {
                                        setSelectedTrait(trait.skill);
                                        setMascotMood(trait.value >= 70 ? "celebrate" : "thinking");
                                        setMascotMsg(
                                            trait.value >= 70
                                                ? `Wow! Your ${trait.skill} score is amazing at ${trait.value}%! `
                                                : `Your ${trait.skill} is at ${trait.value}%. Let's level it up together! `
                                        );
                                    }}
                                    style={{
                                        padding: "12px 14px",
                                        borderRadius: 12,
                                        marginBottom: 8,
                                        background: selectedTrait === trait.skill ? `${detail.color}10` : "rgba(255,255,255,0.02)",
                                        border: `1px solid ${selectedTrait === trait.skill ? `${detail.color}40` : "rgba(255,255,255,0.05)"}`,
                                        cursor: "pointer",
                                        transition: "all 0.2s ease",
                                    }}
                                >
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                                        <span style={{ fontWeight: 600, fontSize: "0.9rem" }}>{trait.skill}</span>
                                        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                            <span style={{ fontSize: "0.75rem", color: comment.color, fontWeight: 700 }}>
                                                {comment.label}
                                            </span>
                                            <span style={{ fontFamily: "var(--font-display)", fontWeight: 800, color: detail.color, fontSize: "1rem" }}>
                                                {animatedValues[i]}%
                                            </span>
                                        </div>
                                    </div>
                                    <div className="progress-bar">
                                        <div
                                            style={{
                                                height: "100%",
                                                borderRadius: 3,
                                                background: "var(--bg-tertiary)",
                                                width: `${animatedValues[i]}%`,
                                                transition: "width 0.05s linear",
                                            }}
                                        />
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    {/* Trait detail card */}
                    {selected && selectedTrait && (
                        <div
                            className="glass-card"
                            style={{
                                padding: 20,
                                border: `1px solid ${selected.color}30`,
                                background: `${selected.color}06`,
                                animation: "slideInUp 0.3s ease",
                            }}
                        >
                            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                                <h3 style={{ fontWeight: 700, color: selected.color, fontSize: "1rem" }}>
                                    {selectedTrait}
                                </h3>
                                <span
                                    style={{
                                        fontFamily: "var(--font-display)",
                                        fontSize: "2rem",
                                        fontWeight: 800,
                                        color: selected.color,
                                    }}
                                >
                                    {selectedTraitData?.value}%
                                </span>
                            </div>
                            <p style={{ color: "var(--white-muted)", fontSize: "0.85rem", lineHeight: 1.6, marginBottom: 14 }}>
                                {selected.desc}
                            </p>
                            <div style={{ fontSize: "0.8rem", fontWeight: 700, color: "var(--white-secondary)", marginBottom: 8 }}>
                                 Improvement Tips:
                            </div>
                            {selected.tips.map((tip, i) => (
                                <div
                                    key={i}
                                    style={{
                                        display: "flex",
                                        alignItems: "flex-start",
                                        gap: 8,
                                        marginBottom: 6,
                                        fontSize: "0.82rem",
                                        color: "var(--white-muted)",
                                    }}
                                >
                                    <span style={{ color: selected.color, marginTop: 1 }}>ΓåÆ</span>
                                    {tip}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";
import { useState } from "react";
import { skillGaps } from "@/lib/data";
import { CheckCircle2, ChevronDown, ChevronUp, AlertCircle } from "lucide-react";

export default function SkillGapsPage() {
    const [closedGaps, setClosedGaps] = useState<number[]>([]);

    const activeGaps = skillGaps.filter((g) => !closedGaps.includes(g.id));
    const resolvedGaps = skillGaps.filter((g) => closedGaps.includes(g.id));

    const toggleGap = (id: number) => {
        if (closedGaps.includes(id)) {
            setClosedGaps(closedGaps.filter((g) => g !== id));
        } else {
            setClosedGaps([...closedGaps, id]);
        }
    };

    return (
        <div style={{ maxWidth: 1000, margin: "0 auto", animation: "fadeIn 0.5s ease" }}>
            {/* Header */}
            <div style={{ marginBottom: 40 }}>
                <h1 style={{ fontFamily: "var(--font-serif)", fontSize: "2.5rem", fontWeight: 400, color: "var(--text-primary)", marginBottom: 8 }}>
                    Skill <span style={{ fontStyle: "italic", color: "var(--text-secondary)" }}>Gaps</span>
                </h1>
                <p style={{ color: "var(--text-secondary)", fontSize: "1.05rem" }}>
                    Identify and address your weak points to maximize job readiness.
                </p>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 32, alignItems: "start" }}>

                {/* Active Gaps */}
                <div>
                    <h2 style={{ fontSize: "1.2rem", fontWeight: 500, color: "var(--text-primary)", marginBottom: 20, display: "flex", alignItems: "center", gap: 10 }}>
                        <AlertCircle size={20} color="var(--accent)" /> Active Gaps ({activeGaps.length})
                    </h2>

                    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                        {activeGaps.map((gap) => (
                            <div key={gap.id} className="stat-card" style={{ padding: 24, borderLeft: `4px solid ${gap.impactColor}` }}>
                                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                                    <h3 style={{ fontSize: "1.1rem", fontWeight: 600, color: "var(--text-primary)" }}>{gap.skill}</h3>
                                    <span style={{ fontSize: "0.75rem", padding: "4px 10px", borderRadius: 100, background: "var(--bg-tertiary)", color: gap.impactColor, fontWeight: 600 }}>
                                        {gap.impact} Priority
                                    </span>
                                </div>
                                <p style={{ fontSize: "0.85rem", color: "var(--text-secondary)", marginBottom: 16 }}>{gap.careerImpact}</p>

                                <div style={{ padding: "12px", background: "var(--bg-tertiary)", borderRadius: 8, marginBottom: 16 }}>
                                    <span style={{ fontSize: "0.8rem", fontWeight: 600, color: "var(--text-primary)" }}>Recommendation:</span>
                                    <div style={{ fontSize: "0.85rem", color: "var(--text-muted)", marginTop: 4 }}>{gap.learningPath[0]}</div>
                                </div>

                                <button onClick={() => toggleGap(gap.id)} className="btn-primary" style={{ width: "100%", padding: 10, fontSize: "0.85rem", display: "flex", justifyContent: "center", gap: 8 }}>
                                    <CheckCircle2 size={16} /> Mark as Resolved
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Resolved Gaps */}
                <div>
                    <h2 style={{ fontSize: "1.2rem", fontWeight: 500, color: "var(--text-primary)", marginBottom: 20, display: "flex", alignItems: "center", gap: 10 }}>
                        <CheckCircle2 size={20} color="#22c55e" /> Resolved Gaps ({resolvedGaps.length})
                    </h2>

                    {resolvedGaps.length === 0 ? (
                        <div style={{ padding: 40, textAlign: "center", background: "var(--bg-tertiary)", borderRadius: 16, border: "1px dashed var(--border-light)", color: "var(--text-muted)", fontSize: "0.9rem" }}>
                            No gaps resolved yet. Keep pushing!
                        </div>
                    ) : (
                        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                            {resolvedGaps.map((gap) => (
                                <div key={gap.id} className="stat-card" style={{ padding: 20, opacity: 0.7, border: "1px solid #22c55e30", background: "var(--bg-secondary)" }}>
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                                        <h3 style={{ fontSize: "1rem", fontWeight: 500, color: "var(--text-primary)", textDecoration: "line-through" }}>{gap.skill}</h3>
                                        <CheckCircle2 size={18} color="#22c55e" />
                                    </div>
                                    <button onClick={() => toggleGap(gap.id)} style={{ background: "none", border: "none", color: "var(--text-muted)", fontSize: "0.75rem", cursor: "pointer", textDecoration: "underline" }}>
                                        Re-open gap
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
}

import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "Skill GPS ΓÇö AI-Powered Career Development Platform",
  description: "Analyze your academic data, identify skill gaps, and get personalized career roadmaps powered by AI. Track your journey from student to professional.",
  keywords: "skill gaps, career development, AI career mentor, student roadmap, employability",
  openGraph: {
    title: "Skill GPS ΓÇö Navigate Your Career with AI",
    description: "Your AI-powered career GPS. Know where you are, where you're going, and exactly how to get there.",
    type: "website",
  },
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="anonymous" />
        <link
          href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:ital,wght@0,400;0,500;0,600;1,400;1,500&display=swap"
          rel="stylesheet"
        />
      </head>
      <body>{children}</body>
    </html>
  );
}

