"use client";
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { colleges } from "@/lib/data";

type Step = "country" | "college" | "email" | "verify" | "profile" | "success";

const MASCOT_CONFIG: Record<Step, { mood: "idle" | "celebrate" | "thinking" | "wave" | "sad" | "excited"; message: string }> = {
    country: { mood: "wave", message: "Hey there!  I'm Spark, your career companion! Let's find your institution first." },
    college: { mood: "thinking", message: "Hmm, let me find your college... Your institution needs to be registered with us!" },
    email: { mood: "idle", message: "Great choice! Now enter your official college email ID. I'll verify you're really a student! " },
    verify: { mood: "thinking", message: "Let me check our database... Matching your email with student records..." },
    profile: { mood: "excited", message: "Found you!  Let me just confirm a few more details to personalize your experience!" },
    success: { mood: "celebrate", message: "YESSS!  Welcome to Skill GPS, Arjun! Your career GPS is now activated! Let's navigate!" },
};

const DEMO_STUDENTS: Record<string, { name: string; regNo: string; year: number; section: string; dept: string }> = {
    "arjun.sharma@srmist.edu.in": { name: "Arjun Sharma", regNo: "RA2111003010001", year: 3, section: "A", dept: "CSE" },
    "priya.nair@srmist.edu.in": { name: "Priya Nair", regNo: "RA2111003010002", year: 2, section: "B", dept: "CSE" },
    "rahul.m@vituniversity.ac.in": { name: "Rahul Mehta", regNo: "VIT2022CS001", year: 3, section: "C", dept: "IT" },
};

export default function OnboardingPage() {
    const router = useRouter();
    const [step, setStep] = useState<Step>("country");
    const [selectedCountry, setSelectedCountry] = useState<string>("");
    const [selectedCollege, setSelectedCollege] = useState<string>("");
    const [email, setEmail] = useState<string>("");
    const [emailError, setEmailError] = useState<string>("");
    const [verifying, setVerifying] = useState(false);
    const [studentData, setStudentData] = useState<typeof DEMO_STUDENTS[string] | null>(null);
    const [careerGoal, setCareerGoal] = useState<string>("AI Engineer");
    const [emailDomainHint, setEmailDomainHint] = useState<string>("");
    const [collegeSearch, setCollegeSearch] = useState<string>("");
    const [progress, setProgress] = useState(0);

    const STEPS: Step[] = ["country", "college", "email", "verify", "profile", "success"];
    const stepIdx = STEPS.indexOf(step);

    useEffect(() => {
        setProgress(((stepIdx + 1) / STEPS.length) * 100);
    }, [stepIdx]);

    useEffect(() => {
        if (selectedCollege.includes("SRM")) setEmailDomainHint("@srmist.edu.in");
        else if (selectedCollege.includes("VIT")) setEmailDomainHint("@vituniversity.ac.in");
        else if (selectedCollege.includes("NIT")) setEmailDomainHint("@nitt.edu");
        else if (selectedCollege.includes("IIT")) setEmailDomainHint("@iitm.ac.in");
        else setEmailDomainHint("@college.edu.in");
    }, [selectedCollege]);

    const allColleges = colleges.flatMap((c) =>
        c.institutions.map((inst) => ({ name: inst, flag: c.flag, country: c.country }))
    );
    const filteredColleges = allColleges.filter((c) =>
        c.name.toLowerCase().includes(collegeSearch.toLowerCase()) ||
        c.country.toLowerCase().includes(collegeSearch.toLowerCase())
    );

    const handleEmailVerify = async () => {
        setEmailError("");
        if (!email.includes("@") || !email.includes(".")) {
            setEmailError("Please enter a valid email address");
            return;
        }
        setVerifying(true);
        setStep("verify");

        await new Promise((r) => setTimeout(r, 2500));

        const student = DEMO_STUDENTS[email.toLowerCase()];
        if (student) {
            setStudentData(student);
            setStep("profile");
        } else if (email.endsWith(emailDomainHint)) {
            setEmailError("No student record found with this email. Please contact your institution.");
            setStep("email");
        } else {
            setEmailError("Email domain doesn't match your selected college. Try: " + emailDomainHint);
            setStep("email");
        }
        setVerifying(false);
    };

    const maskEmail = (e: string) => {
        const [user, domain] = e.split("@");
        return `${user.slice(0, 3)}***@${domain}`;
    };

    const CAREER_GOALS = ["AI Engineer", "Data Scientist", "Full Stack Developer", "Cloud Architect", "Cybersecurity Expert", "Product Manager", "DevOps Engineer"];

    return (
        <div
            style={{
                minHeight: "100vh",
                background: "var(--black-secondary)",
                display: "flex",
                fontFamily: "var(--font-body)",
                overflow: "hidden",
            }}
            className="grid-bg"
        >
            {/* Left Panel */}
            <div
                style={{
                    width: "45%",
                    background: "linear-gradient(135deg, #00D4FF08, #0066FF08)",
                    borderRight: "1px solid var(--black-border)",
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    justifyContent: "center",
                    padding: "60px 40px",
                    position: "relative",
                }}
                className="hide-mobile"
            >
                {/* Background glow */}
                <div style={{ position: "absolute", top: "30%", left: "30%", width: 300, height: 300, borderRadius: "50%", background: "radial-gradient(circle, rgba(0,212,255,0.08), transparent)", pointerEvents: "none" }} />

                {/* Logo */}
                <div style={{ position: "absolute", top: 32, left: 32, display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ width: 32, height: 32, borderRadius: "8px", background: "linear-gradient(135deg,#00D4FF,#0066FF)", display: "flex", alignItems: "center", justifyContent: "center" }}></div>
                    <span style={{ fontFamily: "var(--font-display)", fontWeight: 700 }}>Skill<span style={{ color: "var(--cyan-primary)" }}>GPS</span></span>
                </div>

                {/* Mascot */}
                <div style={{ marginBottom: 32 }}>
                    
                </div>

                {/* Steps indicator */}
                <div style={{ display: "flex", gap: 8, marginTop: 40 }}>
                    {STEPS.map((s, i) => (
                        <div
                            key={s}
                            style={{
                                height: 4,
                                width: i <= stepIdx ? 32 : 16,
                                borderRadius: 2,
                                background: i <= stepIdx ? "var(--cyan-primary)" : "var(--black-border)",
                                transition: "all 0.3s ease",
                            }}
                        />
                    ))}
                </div>

                {/* Progress text */}
                <p style={{ marginTop: 16, color: "var(--white-muted)", fontSize: "0.85rem" }}>
                    Step {stepIdx + 1} of {STEPS.length}
                </p>

                {/* Feature bullets */}
                <div style={{ marginTop: 40, display: "flex", flexDirection: "column", gap: 12 }}>
                    {[
                        " AI-powered career roadmap",
                        " Real-time skill gap analysis",
                        " 180+ institutions supported",
                        " 100% free for students",
                    ].map((item, i) => (
                        <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, color: i <= stepIdx ? "white" : "var(--white-subtle)", fontSize: "0.88rem", transition: "color 0.3s" }}>
                            <span style={{ color: "var(--cyan-primary)" }}>{item.split(" ")[0]}</span>
                            {item.slice(2)}
                        </div>
                    ))}
                </div>
            </div>

            {/* Right Panel - Form */}
            <div
                style={{
                    flex: 1,
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "center",
                    padding: "60px 5%",
                    overflowY: "auto",
                }}
            >
                {/* Progress bar */}
                <div style={{ marginBottom: 40 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8, fontSize: "0.8rem", color: "var(--white-muted)" }}>
                        <span>Getting started</span>
                        <span style={{ color: "var(--cyan-primary)" }}>{Math.round(progress)}%</span>
                    </div>
                    <div className="progress-bar">
                        <div className="progress-fill-cyan" style={{ width: `${progress}%` }} />
                    </div>
                </div>

                {/* ===== STEP: COUNTRY ===== */}
                {step === "country" && (
                    <div style={{ animation: "slideInUp 0.5s ease" }}>
                        <h1 style={{ fontFamily: "var(--font-display)", fontSize: "2rem", fontWeight: 800, marginBottom: 8 }}>
                            Where are you from? 
                        </h1>
                        <p style={{ color: "var(--white-muted)", marginBottom: 32 }}>Select your country to find your institution</p>

                        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: 14 }}>
                            {colleges.map((c) => (
                                <button
                                    key={c.country}
                                    onClick={() => { setSelectedCountry(c.country); setStep("college"); }}
                                    style={{
                                        padding: "20px 16px",
                                        borderRadius: 14,
                                        border: `1px solid ${selectedCountry === c.country ? "var(--cyan-primary)" : "var(--black-border)"}`,
                                        background: selectedCountry === c.country ? "rgba(0,212,255,0.1)" : "var(--black-card)",
                                        cursor: "pointer",
                                        textAlign: "center",
                                        transition: "all 0.2s",
                                        color: "white",
                                    }}
                                    onMouseEnter={(e) => { e.currentTarget.style.borderColor = "var(--cyan-primary)"; e.currentTarget.style.transform = "translateY(-3px)"; }}
                                    onMouseLeave={(e) => { e.currentTarget.style.borderColor = selectedCountry === c.country ? "var(--cyan-primary)" : "var(--black-border)"; e.currentTarget.style.transform = "translateY(0)"; }}
                                >
                                    <div style={{ fontSize: "2rem", marginBottom: 8 }}>{c.flag}</div>
                                    <div style={{ fontWeight: 600, fontSize: "0.9rem" }}>{c.country}</div>
                                    <div style={{ color: "var(--white-muted)", fontSize: "0.75rem", marginTop: 2 }}>{c.institutions.length} institutions</div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* ===== STEP: COLLEGE ===== */}
                {step === "college" && (
                    <div style={{ animation: "slideInUp 0.5s ease" }}>
                        <button onClick={() => setStep("country")} style={{ background: "none", border: "none", color: "var(--white-muted)", cursor: "pointer", marginBottom: 20, fontSize: "0.9rem", display: "flex", alignItems: "center", gap: 6 }}>
                            ΓåÉ Back
                        </button>
                        <h1 style={{ fontFamily: "var(--font-display)", fontSize: "2rem", fontWeight: 800, marginBottom: 8 }}>
                            Select your institution 
                        </h1>
                        <p style={{ color: "var(--white-muted)", marginBottom: 24 }}>
                            Showing institutions in <strong style={{ color: "white" }}>{selectedCountry}</strong>
                        </p>

                        {/* Search */}
                        <div style={{ marginBottom: 20, position: "relative" }}>
                            <span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", fontSize: "1rem" }}></span>
                            <input
                                className="input-field"
                                placeholder="Search your college..."
                                value={collegeSearch}
                                onChange={(e) => setCollegeSearch(e.target.value)}
                                style={{ paddingLeft: 42 }}
                            />
                        </div>

                        <div style={{ display: "flex", flexDirection: "column", gap: 10, maxHeight: 400, overflowY: "auto" }}>
                            {filteredColleges
                                .filter((c) => c.country === selectedCountry || !selectedCountry || collegeSearch)
                                .map((c) => (
                                    <button
                                        key={c.name}
                                        onClick={() => { setSelectedCollege(c.name); setStep("email"); }}
                                        style={{
                                            padding: "16px 20px",
                                            borderRadius: 12,
                                            border: "1px solid var(--black-border)",
                                            background: "var(--black-card)",
                                            cursor: "pointer",
                                            textAlign: "left",
                                            color: "white",
                                            transition: "all 0.2s",
                                            display: "flex",
                                            alignItems: "center",
                                            justifyContent: "space-between",
                                        }}
                                        onMouseEnter={(e) => { e.currentTarget.style.borderColor = "var(--cyan-primary)"; e.currentTarget.style.background = "rgba(0,212,255,0.05)"; }}
                                        onMouseLeave={(e) => { e.currentTarget.style.borderColor = "var(--black-border)"; e.currentTarget.style.background = "var(--black-card)"; }}
                                    >
                                        <span style={{ fontSize: "0.95rem", fontWeight: 500 }}>
                                            {c.flag} {c.name}
                                        </span>
                                        <span style={{ color: "var(--white-muted)", fontSize: "0.8rem" }}>ΓåÆ</span>
                                    </button>
                                ))}
                        </div>
                    </div>
                )}

                {/* ===== STEP: EMAIL ===== */}
                {step === "email" && (
                    <div style={{ animation: "slideInUp 0.5s ease" }}>
                        <button onClick={() => setStep("college")} style={{ background: "none", border: "none", color: "var(--white-muted)", cursor: "pointer", marginBottom: 20, fontSize: "0.9rem", display: "flex", alignItems: "center", gap: 6 }}>
                            ΓåÉ Back
                        </button>
                        <h1 style={{ fontFamily: "var(--font-display)", fontSize: "2rem", fontWeight: 800, marginBottom: 8 }}>
                            Verify your identity 
                        </h1>
                        <p style={{ color: "var(--white-muted)", marginBottom: 8 }}>
                            Enter your official college email from{" "}
                            <strong style={{ color: "white" }}>{selectedCollege}</strong>
                        </p>
                        <p style={{ color: "var(--cyan-primary)", fontSize: "0.85rem", marginBottom: 28 }}>
                             Your email should end with <strong>{emailDomainHint}</strong>
                        </p>

                        {/* Demo hint */}
                        <div style={{ background: "rgba(255,107,0,0.08)", border: "1px solid rgba(255,107,0,0.2)", borderRadius: 10, padding: "10px 14px", marginBottom: 20, fontSize: "0.82rem", color: "var(--orange-primary)" }}>
                             <strong>Demo:</strong> Try <code style={{ background: "rgba(255,107,0,0.15)", padding: "2px 6px", borderRadius: 4 }}>arjun.sharma@srmist.edu.in</code>
                        </div>

                        <div style={{ marginBottom: 16 }}>
                            <label style={{ display: "block", fontSize: "0.85rem", color: "var(--white-muted)", marginBottom: 8 }}>College Email ID</label>
                            <input
                                className="input-field"
                                type="email"
                                placeholder={`yourname${emailDomainHint}`}
                                value={email}
                                onChange={(e) => { setEmail(e.target.value); setEmailError(""); }}
                                onKeyDown={(e) => e.key === "Enter" && handleEmailVerify()}
                            />
                            {emailError && (
                                <p style={{ color: "#FF3B3B", fontSize: "0.82rem", marginTop: 6 }}> {emailError}</p>
                            )}
                        </div>

                        <button className="btn-primary" onClick={handleEmailVerify} style={{ width: "100%", padding: "16px" }}>
                            Verify & Continue ΓåÆ
                        </button>

                        <p style={{ color: "var(--white-subtle)", fontSize: "0.82rem", marginTop: 16, textAlign: "center" }}>
                            Your institution must be pre-registered. <a href="#" style={{ color: "var(--cyan-primary)", textDecoration: "none" }}>Contact admin ΓåÆ</a>
                        </p>
                    </div>
                )}

